import UIKit
import Foundation

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {

    var window: UIWindow?

    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard let url = userActivity.webpageURL else {
            return false
        }
        handleDeepLink(url: url)
        return true
    }

    private func handleDeepLink(url: URL) {
        let components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        let queryItems = components?.queryItems

        let promoCode = queryItems?.first(where: { $0.name == "code" })?.value
        let discount = queryItems?.first(where: { $0.name == "discount" })?.value

        applyPromoCode(promoCode: promoCode, discount: discount)
    }

    private func applyPromoCode(promoCode: String?, discount: String?) {
        guard let code = promoCode, let discountStr = discount, let discountValue = Int(discountStr) else {
            return
        }
        
        // Assuming a UserAccount singleton to apply the promo
        UserAccount.shared.applyPromo(code: code, discount: discountValue)
    }
}

class UserAccount {
    static let shared = UserAccount()

    private init() {}

    func applyPromo(code: String, discount: Int) {
        // Code to apply the promo code and discount to the user's account
        print("Applied promo code: \(code) with discount: \(discount)%")
    }
}